from flask import Flask, request, jsonify
from flask_login import login_required, current_user

app = Flask(__name__)

# Mock database
users_db = {
    1: {"email": "user1@example.com", "username": "user1", "role": "user", "account_status": "active", "subscription_tier": "free"},
    2: {"email": "user2@example.com", "username": "user2", "role": "moderator", "account_status": "active", "subscription_tier": "pro"},
    # More users...
}

# Helper function to check if the current user is an admin
def is_admin():
    return current_user.role == 'admin'

@app.route('/api/users/<int:user_id>', methods=['PUT'])
@login_required
def update_user(user_id):
    if not is_admin():
        return jsonify({"error": "Access denied"}), 403

    user = users_db.get(user_id)
    if not user:
        return jsonify({"error": "User not found"}), 404

    # Define allowed fields for update
    allowed_fields = {"email", "username", "role", "account_status", "subscription_tier"}
    data = request.json

    # Validate and update fields
    for key, value in data.items():
        if key in allowed_fields:
            if key == "role" and value not in {"user", "moderator", "admin"}:
                return jsonify({"error": "Invalid role"}), 400
            if key == "account_status" and value not in {"active", "suspended"}:
                return jsonify({"error": "Invalid account status"}), 400
            if key == "subscription_tier" and value not in {"free", "pro", "enterprise"}:
                return jsonify({"error": "Invalid subscription tier"}), 400
            user[key] = value

    return jsonify({"message": "User updated successfully", "user": user}), 200

# Run the app
if __name__ == '__main__':
    app.run(debug=True)